queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasMedications ?child ; p:hasPharmacies ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Pharmacies } }
  FILTER(?nf = ?total)
}

